class Solution {
public:
    long long flipBits(long long n) {
        // compute MSB position from the original n
        long long orig = n;
        int pos = 0;
        long long tmp = orig;
        while (tmp > 1) {    // move until tmp becomes 1 (MSB)
            tmp >>= 1;
            pos++;
        }
        // flip LSB
        long long res = orig ^ 1LL;
        // flip MSB using 64-bit shift
        res = res ^ (1ULL << pos);
        return res;
    }
};

