class Solution {
  flipBits(n) {
    // accept Number or BigInt input
    let x = (typeof n === 'bigint') ? n : BigInt(n);

    // optional: handle 0 if you want a defined behavior
    if (x === 0n) return 1; // returns Number 1

    // find MSB position from the ORIGINAL number
    let tmp = x;
    let pos = 0n;
    while (tmp > 1n) {    // stop when tmp becomes 1 (that is MSB)
      tmp >>= 1n;
      pos += 1n;
    }

    // flip LSB (bit 0) then flip MSB (bit pos)
    let res = x ^ 1n;
    res = res ^ (1n << pos);

    // convert to Number if safe, otherwise return BigInt
    if (res <= BigInt(Number.MAX_SAFE_INTEGER) && res >= BigInt(Number.MIN_SAFE_INTEGER)) {
      return Number(res);
    }
    return res;
  }
}
